class VM:
    def __init__(self):
        self._v = 0
        self.obs = []
    def bind(self, cb):
        self.obs.append(cb)
    def set(self, x):
        self._v = x
        for cb in self.obs:
            cb(x)

vm = VM()
log = []
vm.bind(lambda x: log.append(x * 2))
vm.set(5)
vm.set(10)
print(log)
